import { ref, reactive, onMounted, computed } from 'vue';
import { ElMessage } from 'element-plus';
import userService from '@/api/user';
import store from '@/store';
export default {
  name: 'ProfileView',
  setup() {
    const userFormRef = ref(null);
    const loading = ref(false);

    // 从 localStorage 获取当前用户信息
    const currentUser = computed(() => store.state.auth.user);
    const userStats = reactive({
      novelCount: 0,
      totalViews: 0,
      favoriteCount: 0
    });
    const userForm = reactive({
      id: '',
      username: '',
      email: '',
      nickname: '',
      createdAt: '',
      lastLoginAt: '',
      oldPassword: '',
      newPassword: '',
      confirmPassword: ''
    });
    const rules = {
      email: [{
        required: true,
        message: '请输入邮箱地址',
        trigger: 'blur'
      }, {
        type: 'email',
        message: '请输入正确的邮箱格式',
        trigger: 'blur'
      }],
      nickname: [{
        max: 50,
        message: '昵称长度不能超过50个字符',
        trigger: 'blur'
      }],
      newPassword: [{
        min: 6,
        message: '密码长度不能少于6个字符',
        trigger: 'blur'
      }],
      confirmPassword: [{
        validator: (rule, value, callback) => {
          if (userForm.newPassword && value !== userForm.newPassword) {
            callback(new Error('两次输入的密码不一致'));
          } else {
            callback();
          }
        },
        trigger: 'blur'
      }]
    };

    // 初始化表单数据
    const initUserForm = () => {
      if (currentUser.value) {
        userForm.id = currentUser.value.id;
        userForm.username = currentUser.value.username;
        userForm.email = currentUser.value.email;
        userForm.nickname = currentUser.value.nickname || '';
        userForm.createdAt = currentUser.value.createdAt;
        userForm.lastLoginAt = currentUser.value.lastLoginAt;

        // 尝试从后端获取最新的用户信息
        fetchCurrentUser();
      }
    };

    // 从后端获取当前用户的最新信息
    const fetchCurrentUser = async () => {
      try {
        const data = await userService.getCurrentUser();
        if (data) {
          // 更新表单数据
          userForm.id = data.id;
          userForm.email = data.email;
          userForm.nickname = data.nickname || '';
          userForm.createdAt = data.createdAt;
          userForm.lastLoginAt = data.lastLoginAt;

          // 更新 store 中的用户信息
          store.commit('auth/updateUserProfile', {
            email: data.email,
            nickname: data.nickname,
            createdAt: data.createdAt,
            lastLoginAt: data.lastLoginAt
          });
        }
      } catch (error) {
        console.error('获取用户信息失败:', error);
      }
    };

    // 获取用户统计信息
    const fetchUserStats = async () => {
      try {
        console.log('开始获取用户统计信息...');
        const data = await userService.getUserStats();
        console.log('获取用户统计信息成功，响应数据:', data);
        if (data) {
          console.log('用户统计数据:', data);
          userStats.novelCount = data.novelCount || 0;
          userStats.totalViews = data.totalViews || 0;
          userStats.favoriteCount = data.favoriteCount || 0;
        } else {
          console.warn('获取用户统计信息响应数据为空');
          // 设置默认值
          userStats.novelCount = 0;
          userStats.totalViews = 0;
          userStats.favoriteCount = 0;
        }
      } catch (error) {
        console.error('获取用户统计信息失败:', error);
        // 出错时设置默认值
        userStats.novelCount = 0;
        userStats.totalViews = 0;
        userStats.favoriteCount = 0;
      }
    };

    // 提交表单
    const submitForm = async () => {
      if (!userFormRef.value) return;
      await userFormRef.value.validate(async valid => {
        if (valid) {
          loading.value = true;
          try {
            // 准备要发送的数据
            const userData = {
              id: userForm.id,
              email: userForm.email,
              nickname: userForm.nickname
            };

            // 如果有输入新密码，则包含密码字段
            if (userForm.newPassword) {
              if (!userForm.oldPassword) {
                ElMessage.error('修改密码需要输入旧密码');
                loading.value = false;
                return;
              }
              userData.oldPassword = userForm.oldPassword;
              userData.newPassword = userForm.newPassword;
            }

            // 发送更新请求
            await userService.updateUserProfile(userData);
            ElMessage.success('个人信息更新成功');

            // 更新 store 中的用户信息
            store.commit('auth/updateUserProfile', {
              email: userForm.email,
              nickname: userForm.nickname
            });

            // 清空密码字段
            userForm.oldPassword = '';
            userForm.newPassword = '';
            userForm.confirmPassword = '';
          } catch (error) {
            console.error('更新个人信息失败:', error);
            ElMessage.error(error.response?.data?.message || '更新个人信息失败');
          } finally {
            loading.value = false;
          }
        }
      });
    };

    // 重置表单
    const resetForm = () => {
      if (userFormRef.value) {
        userFormRef.value.resetFields();
        initUserForm();
      }
    };

    // 格式化日期
    const formatDate = dateString => {
      if (!dateString) return '未知';
      try {
        const date = new Date(dateString);
        // 检查日期是否有效
        if (isNaN(date.getTime())) return '未知';

        // 对于当天的日期，显示"今天 HH:MM"
        const today = new Date();
        if (date.getDate() === today.getDate() && date.getMonth() === today.getMonth() && date.getFullYear() === today.getFullYear()) {
          return `今天 ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
        }

        // 1970年表示日期未设置
        if (date.getFullYear() === 1970) {
          return '未知';
        }
        return date.toLocaleDateString('zh-CN', {
          year: 'numeric',
          month: '2-digit',
          day: '2-digit',
          hour: '2-digit',
          minute: '2-digit'
        });
      } catch (error) {
        console.error('日期格式化错误:', error);
        return '未知';
      }
    };
    onMounted(() => {
      initUserForm();
      fetchUserStats();
    });
    return {
      userFormRef,
      userForm,
      userStats,
      rules,
      loading,
      submitForm,
      resetForm,
      formatDate
    };
  }
};
